# --- Secure password hashing using PBKDF2 (stdlib, no extra deps) ---

def hash_password(password):
    """Hash a password using PBKDF2-HMAC-SHA256 with a random salt."""
    salt = os.urandom(32)
    iterations = 260000  # OWASP recommended minimum for PBKDF2-SHA256
    dk = hashlib.pbkdf2_hmac('sha256', password.encode('utf-8'), salt, iterations)
    return {
        'salt': salt.hex(),
        'hash': dk.hex(),
        'iterations': iterations,
        'algorithm': 'pbkdf2_sha256'
    }


def verify_password(password, stored):
    """Verify a password against a stored hash using constant-time comparison."""
    salt = bytes.fromhex(stored['salt'])
    iterations = stored.get('iterations', 260000)
    dk = hashlib.pbkdf2_hmac('sha256', password.encode('utf-8'), salt, iterations)
    return hmac.compare_digest(dk.hex(), stored['hash'])


