# --- Rate limiting ---

def _get_rate_limit_key(username):
    """Create a rate limit key combining IP and username."""
    ip = request.remote_addr or 'unknown'
    return f"{ip}:{username}"


def is_rate_limited(username):
    """Check if login attempts are rate limited."""
    key = _get_rate_limit_key(username)
    record = login_attempts.get(key)
    if record is None:
        return False
    if record.get('locked_until') and time.time() < record['locked_until']:
        return True
    if record.get('locked_until') and time.time() >= record['locked_until']:
        # Lockout expired, reset
        login_attempts.pop(key, None)
        return False
    return False


def record_failed_login(username):
    """Record a failed login attempt and lock out if threshold exceeded."""
    key = _get_rate_limit_key(username)
    record = login_attempts.get(key, {'count': 0, 'locked_until': None})
    record['count'] += 1
    if record['count'] >= app.config['MAX_LOGIN_ATTEMPTS']:
        record['locked_until'] = time.time() + app.config['LOGIN_LOCKOUT_DURATION']
    login_attempts[key] = record


def clear_failed_logins(username):
    """Clear failed login attempts after successful login."""
    key = _get_rate_limit_key(username)
