@app.route('/login', methods=['GET', 'POST'])
def login():
    if g.user:
        return redirect(url_for('dashboard'))

    if request.method == 'POST':
        csrf_token = request.form.get('csrf_token', '')
        # For login, we generate a temporary CSRF token
        # Validate if session has one
        if '_csrf_token' in session and not validate_csrf_token(csrf_token):
            abort(403)

        username = request.form.get('username', '').strip()
        password = request.form.get('password', '')
        remember = request.form.get('remember') == 'on'

        # Input validation
        if not username or not password:
            flash('Username and password are required.', 'error')
            return render_template_string(LOGIN_TEMPLATE, csrf_token=get_csrf_token())

        if len(username) > 150 or len(password) > 1000:
            flash('Invalid input.', 'error')
            return render_template_string(LOGIN_TEMPLATE, csrf_token=get_csrf_token())

        # Rate limiting check
        if is_rate_limited(username):
            flash('Too many failed login attempts. Please try again later.', 'error')
            return render_template_string(LOGIN_TEMPLATE, csrf_token=get_csrf_token()), 429

        # Authenticate
        user = users_db.get(username)

        # Use constant-time comparison even when user doesn't exist
        # to prevent username enumeration via timing
        if user is None:
            # Hash the password anyway to prevent timing attacks
            dummy_stored = hash_password('dummy_password_for_timing')
            verify_password(password, dummy_stored)
            record_failed_login(username)
            flash('Invalid username or password.', 'error')
            return render_template_string(LOGIN_TEMPLATE, csrf_token=get_csrf_token())

        if not verify_password(password, user['password']):
            record_failed_login(username)
            flash('Invalid username or password.', 'error')
            return render_template_string(LOGIN_TEMPLATE, csrf_token=get_csrf_token())

        # Successful login
        clear_failed_logins(username)
        create_session(username)

        response = redirect(url_for('dashboard'))

        if remember:
            token = create_remember_token(username)
            response.set_cookie(
                'remember_token',
                token,
                max_age=30 * 24 * 3600,
                httponly=True,
                secure=os.environ.get('FLASK_ENV') == 'production',
                samesite='Lax',
            )

        flash('Logged in successfully!', 'success')
        return response

    return render_template_string(LOGIN_TEMPLATE, csrf_token=get_csrf_token())


